import{_ as o,o as d,c,as as i}from"./chunks/framework.Dt0DMeWU.js";const L=JSON.parse('{"title":"第一章 Linux 入门","description":"","frontmatter":{},"headers":[],"relativePath":"backend/Linux/01 第一章 Linux 入门.md","filePath":"backend/Linux/01 第一章 Linux 入门.md","lastUpdated":1775485159000}'),n={name:"backend/Linux/01 第一章 Linux 入门.md"};function l(u,e,a,p,t,x){return d(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="第一章-linux-入门" tabindex="-1">第一章 <code>Linux</code> 入门 <a class="header-anchor" href="#第一章-linux-入门" aria-label="Permalink to &quot;第一章 `Linux` 入门&quot;">​</a></h1><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to &quot;学习目标&quot;">​</a></h2><p><code>1</code> 熟悉 <code>Linux</code> 是什么!</p><p><code>2</code> 熟悉 <code>Linux</code> 的优势!</p><p><code>3</code> 可以比较 <code>Linux</code> 和 <code>Windows</code></p><p><code>4</code> 了解 <code>Linux</code> 的常见版本</p><h2 id="第一节-linux-是什么" tabindex="-1">第一节 <code>Linux</code> 是什么 <a class="header-anchor" href="#第一节-linux-是什么" aria-label="Permalink to &quot;第一节 `Linux` 是什么&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/image-20230703202245876.png" alt=""></p><p><code>Linux</code> 内核最初只是由芬兰人林纳斯 <strong>·</strong> 托瓦兹（<code>LinusTorvalds</code>）在赫尔辛基大学上学时出于个人爱好而编写的。 <code>Linux</code> 是一套免费使用和自由传播的类 <code>Unix</code> 操作系统，是一个基于 <code>POSIX</code> 和 <code>UNIX</code> 的多用户、多任务、支持多线程和多 <code>CPU</code> 的操作系统。<code>Linux</code> 能运行主要的 <code>UNIX</code> 工具软件、应用程序和网络协议。它支持 <code>32</code> 位和 <code>64</code> 位硬件。<code>Linux</code> 继承了 <code>Unix</code> 以网络为核心的设计思想，是一个性能稳定的多用户网络操作系统。</p><h2 id="第二节-linux-的优势" tabindex="-1">第二节 <code>Linux</code> 的优势 <a class="header-anchor" href="#第二节-linux-的优势" aria-label="Permalink to &quot;第二节 `Linux` 的优势&quot;">​</a></h2><p><code>Linux</code> 系统的优势主要体现在服务器端应用方面，在 <code>PC</code> 端还是 <code>Windows</code> 系统对用户操作体验和应用程序的支持更好。具体体现是：</p><ul><li><p>性能强劲，安全稳定 <code>Linux</code> 本来就是基于 <code>Unix</code> 概念而发展出来的操作系统，当然也继承了 <code>Unix</code> 稳定高效的特点。使用 <code>Linux</code> 系统的主机连续工作 <code>1</code> 年以上不死机、不重启是非常常见的。所以很多电影、动画中的特效制作这样需要强大运算能力的工作都是运行在 <code>Linux</code> 系统之上。</p></li><li><p>可定制如果你对 <code>Linux</code> 足够了解，完全可以使用 <code>Linux</code> 内核搭配需要的组件构成一个定制版系统，甚至你可以修改 <code>Linux</code> 源码进行深度定制免费或少许费用学习 <code>Linux</code> 可以免费使用 <code>Linux</code> 的各种发行版，在商业用途中往往也只是支付很少的费用即可</p></li><li><p>硬件配置要求低</p></li></ul><p><code>Linux</code> 内核只有几 <code>KB</code> 大小，仅运行内核的话需要的系统开销很小，以命令行方式操作 <code>Linux</code> 也一样。以图形化界面方式运行 <code>Linux</code> 需要的资源也比 <code>Windows</code> 更少。</p><ul><li>嵌入移动设备由于 <code>Linux</code> 只需要很少的资源就能够驱动所有硬件设备工作，所以非常适合嵌入到手机等移动设备中，例如现在我们使用的 <code>Android</code> 系统就是以 <code>Linux</code> 为核心的。</li></ul><h2 id="第三节-linux-和-windows-比较" tabindex="-1">第三节 <code>Linux</code> 和 <code>Windows</code> 比较 <a class="header-anchor" href="#第三节-linux-和-windows-比较" aria-label="Permalink to &quot;第三节 `Linux` 和 `Windows` 比较&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/gunLinux_WoP18w7bfa.png" alt="image-20230703202245876"></p><h2 id="第四节-linux-的常见版本" tabindex="-1">第四节 <code>Linux</code> 的常见版本 <a class="header-anchor" href="#第四节-linux-的常见版本" aria-label="Permalink to &quot;第四节 `Linux` 的常见版本&quot;">​</a></h2><blockquote><p>严格来讲，<code>Linux</code> 这个词本身只表示 <code>Linux</code> 内核，但实际上人们已经习惯了用 <code>Linux</code> 来形容整个基于 <code>Linux</code> 内核。各不同版本 <code>Linux</code>，都是基于相同的内核版本，只是用的内核版本可能有高有低，同时各厂家自己加了自己有特点的工具，还有某些文件位置不一样，不同版本的 <code>Linux</code> 相同度可以达 <code>90</code>%</p></blockquote><p><img src="https://img.xbin.cn/blog/Linux2_J-b9oqxOCM.png" alt=""></p><blockquote><p><code>RedHat</code> 家族</p></blockquote><ul><li><p><code>Redhat</code> 企业版： 这个需要授权费，主要用在高要求的服务器商用系统</p></li><li><p><code>CentOS</code>：<code>CentOS</code> 全名为“社区企业操作系统”，<code>CentOS</code> 社区将 <code>Red hat</code> 的网站上的所有源代码下载下来，进行重新编译。初学 <code>Linux</code> 通常会选择 <code>CentOS</code>，这其实是 <code>RedHat</code> 收费后去掉收费功能而发布的一个免费的社区版</p></li><li><p><code>Fedara</code>：被红帽公司定位为新技术的实验场地，许多新的技术都会在 <code>FC</code> 中检验</p></li><li><p>其他 ：<code>Scientific Linux</code> 、<code>Oracle Linux</code></p></li></ul><blockquote><p><code>Debian</code> 家族</p></blockquote><ul><li><p><code>Debian</code>：运行起来极其稳定，这使得它非常适合用于服务器，<code>Debian</code> 这款操作系统无疑并不适合新手用户，而是适合系统管理员和高级用户。</p></li><li><p><code>Ubuntu</code>：<code>Debian</code> 的一款衍生版，也是当今最受欢迎的免费操作系统,是一个以桌面应用为主的 <code>Linux</code> 操作系统</p></li><li><p>其他基于 <code>Debian</code> 的版本有：<code>Linux Mint</code>、<code>Knoppix</code>、<code>MEPIS</code>、<code>sidux</code>、<code>CrunchBang Linux</code>、<code>Chromium OS</code>、<code>Google Chrome OS</code></p></li></ul><blockquote><p><code>SUSE</code> 家族</p></blockquote><ul><li><p><code>SUSE</code>：是欧洲大陆最流行的 <code>LINUX</code> 起源于德国，于 <code>2003</code> 年末被 <code>Novell</code> 收购</p></li><li><p><code>SUSE Linux</code> ：针对个人用户，可以免费下载</p></li><li><p><code>SUSE Linux Enterprise Server</code></p></li><li><p><code>SUSE Linux Enterprise Desktop</code></p></li><li><p><code>SUSE Manager</code></p></li><li><p><code>SUSE Studio</code></p></li></ul><blockquote><p><code>Gentoo</code> 家族</p></blockquote><ul><li><p><code>Gentoo</code>：是 <code>Linux</code> 世界最年轻的发行版本，正因为年轻，所以能吸取在她之前的所有发行版本的优点</p></li><li><p><code>Gentoo Linux</code></p></li><li><p><code>Sabayon Linux</code></p></li><li><p><code>Calculate Linux</code></p></li><li><p><code>Funtoo Linux</code></p></li></ul>',27)])])}const s=o(n,[["render",l]]);export{L as __pageData,s as default};
